案例代码：
library ieee;
use ieee.std_logic_1164.all;
use ieee.std_logic_arith.all;
entity add_s is
port (
	arg_a: in unsigned;
	arg_b: in signed;
	y_out: out std_logic_vector
);
end entity add_s;
architecture rtl of add_s is
begin
	y_out <= arg_a + arg_b;        //混用了符号操作数和无符号操作数
end architecture rtl;

