案例代码： 
library ieee;
use ieee.std_logic_1164.all;
entity mealy is
port (clock, reset: in std_logic;
	data_out: out std_logic;
	data_in: in std_logic_vector (1 downto 0));
end mealy;
architecture behave of mealy is
type state_values is (st0, st1, st2, st3, st4);
signal pres_state, next_state: state_values;
begin

--时序逻辑进程定义现态寄存器
statereg: process (clock, reset)  
begin
	if (reset = '0') then
		pres_state <= st0;
	elsif (clock'event and clock ='1') then
		pres_state <= next_state;
	end if;
end process statereg;  
--组合逻辑进程定义次态逻辑
fsm: process (pres_state, data_in)
begin
case pres_state is
when st0 =>
	case data_in is
		when "00" => next_state <= st0;
		when "01" => next_state <= st4;
		when "10" => next_state <= st1;
		when "11" => next_state <= st2;
		when others => next_state <= st0;
	end case;
when st1 =>
	case data_in is
		when "00" => next_state <= st0;
		when "10" => next_state <= st2;
		when others => next_state <= st1;
	end case;
when st2 =>
	case data_in is
		when "00" => next_state <= st1;
		when "01" => next_state <= st1;
		when "10" => next_state <= st3;
		when "11" => next_state <= st3;
		when others => next_state <= st1;
	end case;
when st3 =>
	case data_in is
		when "01" => next_state <= st4;
		when "11" => next_state <= st4;
		when others => next_state <= st3;
	end case;
when st4 =>
	case data_in is	
		when "11" => next_state <= st4;
		when others => next_state <= st0;
	end case;
		when others => next_state <= st0;
	end case;
end process fsm;	
--组合逻辑进程定义输出逻辑
outputs: process (pres_state, data_in)
begin
case pres_state is
	when st0 =>
		case data_in is
		when "00" => data_out <= '0';
		when others => data_out <= '1';
		end case;
	when st1 => data_out <= '0';
	when st2 =>
		case data_in is
		when "00" => data_out <= '0';
		when "01" => data_out <= '0';
		when others => data_out <= '1';
		end case;
	when st3 => data_out <= '1';
	when st4 =>
		case data_in is
		when "10" => data_out <= '1';
		when "11" => data_out <= '1';
		when others => data_out <= '0';
		end case;
	when others => data_out <= '0';
end case;
end process outputs;
end behave;

案例代码：
process ( SEL, X_IN, Z_IN, TMP_STORAGE ) begin       //不宜在同一个顺序块中描述2 个或更多的if 或case 语句
if( SEL = '1' ) then                                 //if 语句在顺序块中
	TMP_STORAGE <= X_IN + Z_IN;
else
	TMP_STORAGE <= X_IN - Z_IN;
end if
LO_B = TMP_STORAGE[31];
if( TMP_STORAGE(7 downto 0) = X"00" ) then       //if 语句在同一个顺序块中
	Z_REG <= '1';
else
	Z_REG <= '0';
end if
if( LO_B = '1' and Z_REG = '0' ) then                //if 语句在同一个顺序块中
	X_REG <= '1';
else
	X_REG <= '0';
end if
	R_REG <= TMP_STORAGE(30 downto 0);
end process

案例代码：
entity t_sll is
  port( clk_1             :in  std_logic;
		clk_2             :in  std_logic;
		in_A            :in  std_logic ;
		out_1              :out std_logic 
	   );
end t_sll;

architecture Behavioral of t_sll is 
  signal in_A1: std_logic := '0';
  signal in_A2: std_logic := '0';
  signal in_A3: std_logic := '0';
begin
process (clk_1) begin
	if(clk_1'event and clk_1 = '1') then
		in_A1 <= in_A AND in_A2;		//为缓解亚稳态，不允许在同步器的第一级触发器之后存在一个反馈循环
	end if;
end process;

process (clk_2) begin
	if(clk_2'event and clk_2 = '1') then
		in_A2<= in_A1;
		in_A3 <= in_A2;
		out_1 <= in_A3;
	end if;
end process;
end Behavioral;

案例代码：
entity sr is
port (
	clk, reset, data_a, data_b: in std_logic;
	Q: out std_logic
 );
end;
architecture rtl of sr is
signal trf12: std_logic;
begin
process ( trf12, reset ) begin
if reset = '1' then
	Q <= '0';
elsif (trf12'event and trf12='1') then
	Q <= data_b;                     //触发器的时钟端“sr.Q”被另一触发器的输出所驱动。时钟树综合工具将无法考虑时钟的平衡
end if;
end process;
process ( clk, reset ) begin
if reset = '1' then
	trf12 <= '0';
elsif (clk'event and clk='1') then
	trf12 <= data_a;              //时钟端由触发器“sr.trf12”所驱动
end if;
end process;
end;

案例代码：
entity t_sll is
  port( clk_1             :in  std_logic;
		clk_2             :in  std_logic;
		in_A            :in  std_logic   ;
		out_1              :out std_logic 
	   );
end t_sll;

architecture Behavioral of t_sll is  
  signal in_A1: std_logic := '0';
  signal in_A2: std_logic := '0';
  signal in_A3: std_logic := '0';
  signal in_A4: std_logic := '0';
begin
process (clk_1) begin
	if(clk_1'event and clk_1 = '1') then
		in_A1 <= in_A;
	end if;
end process;

process (in_A1) begin
	in_A2 <= not in_A1;		//组合逻辑不应置于两个时钟域之间
end process;

process (clk_2) begin
	if(clk_2'event and clk_2 = '1') then
		in_A3 <= in_A2;
		in_A4 <= in_A3;
		out_1 <= in_A4;
	end if;
end process;
end Behavioral;

案例代码：
process ( A ) is
variable T: std_logic_vector ( 5 downto 1 );
variable W: std_logic_vector ( 15 downto 1 );
variable R: boolean;
variable E: std_logic_vector ( 10 downto 1 );
begin
if ( T = E ) then                          //关系操作符"="右边的10 位与左边5 位宽度不一致，应保持位宽的一致，避免运算错误。
  Q <= "11";
elsif ( ( W <= E ) >= R ) then             //关系操作符"<="右边的10 位与左边15 位宽度不一致，应保持位宽的一致，避免运算错误。
  Q <= "00";
end if;

案例代码：
signal X: std_logic_vector(7 downto 0);
signal Y,B: std_logic_vector(3 downto 0);
signal EN: std_logic;
X <= B & (others => EN);		//因为赋值给低位的(others => EN)的向量范围不确定，依赖于对上下文的判断，一些逻辑综合工具和仿真器也许会产生错误
Y <= B and (others => EN);		//因为(others => EN)的向量范围不确定，依赖于对上下文的判断，一些逻辑综合工具和仿真器也许会产生错误

案例代码：
entity top is
port (
	  in1, in2, in3, clk1, clk2, reset, sel : in std_logic; //信号“clk1”被同时用作时钟和复位。不要混合使用时钟和复位以免DFT产生问题，此时扫描会排除所有时钟信号连接的部分。
	  out1, out2 : out std_logic
	  );
end entity;
architecture top_rtl of top is
signal mux_to_ff1, mux_to_ff2 : std_logic;
begin
 mux_to_ff2 <= clk1 when sel = '1' else
  in3;
 MUX_INSTANCE : entity mux port map ( in1 =>
clk1, in2 => in2 , sel => sel, out1 => mux_to_ff1
);
 DFF_INSTANCE1 : entity dff port map ( D => in1, CLK => mux_to_ff1, RESET => reset , Q => out1 ); //连接到“top. DFF_INSTANCE1”时钟端。
 DFF_INSTANCE2 : entity dff port map ( D => in1, CLK => clk2, RESET => mux_to_ff2, Q => out2 ); //连接到“top. DFF_INSTANCE2”异步复位端。
end architecture;

案例代码：
entity ff is
port(data0, data1: in std_logic_;
	 Q: out std_logic);
end entity ff;

architecture rtl of ff is
	 signal temp0, temp1: std_logic;
begin
	 temp0 <= data0 and temp1;
	 temp1 <= temp0 or data1;		//检测到类似RS锁存器的组合电路描述，避免使用基本单元生成锁存器，因为时序分析工具会把它看作是组合电路反馈
	 Q <= temp1;
end architecture rtl;

