entity t_sll is
  port( clk_1             :in  std_logic;
		clk_2             :in  std_logic;
		in_A            :in  std_logic   ;
		out_1              :out std_logic 
	   );
end t_sll;

architecture Behavioral of t_sll is  
  signal in_A2: std_logic := '0';
  signal in_A2: std_logic := '0';
  signal in_A3: std_logic := '0';
  signal in_A4: std_logic := '0';
begin
process (clk_1) begin
	if(clk_1'event and clk_1 = '1') then
		in_A1 <= in_A;
	end if;
end process;
process (in_A2) begin
	in_A3 <= NOT in_A2;		//不应在同步电路的采数触发器和下一个触发器之间放置逻辑
end process;
process (clk_2) 
begin
	if(clk_2'event and clk_2 = '1') then
		in_A2 <= in_A1;
		in_A4 <= in_A3;
		out_1 <= in_A4;
	end if;
end process;
end Behavioral;

