  entity R6_1_3_2_5 is		
  port( 
        clk           :in  std_logic; 
        reset         :in  std_logic; 
	    data1,data2   :in  std_logic;
		Q1,Q2         :out std_logic
       );
  end R6_1_3_2_5;

  architecture Behavioral of R6_1_3_2_5 is

  begin

  p1: process(clk,reset)
  begin
    if(reset = '0')then    --violation
	   Q1 <= '0';
    elsif(clk'event and clk='0')then
	   Q1 <= data1;
	   end if;
    end if;
  end process p1;

  p2: process(clk1)
  begin
    if(reset = '1')then    --violation
	   Q2 <= '0';
    elsif(clk'event and clk='0')then
	   Q2 <= data2;
	   end if;
    end if;
  end process p2;
  end Behavioral;

