  entity R6_1_1_2_4 is
  port( 
		rst_n           :in  std_logic;
        clk             :in  std_logic;
		CLOCK_ONLY      :in  std_logic;
	   	cnt_out         :out std_logic_vector (5 downto 0)  
       );
end R6_1_1_2_4;

architecture Behavioral of R6_1_1_2_4 is
	component MUX2x1 is
	port(
		in1: in std_logic;
		in2: in std_logic;
		sel: in std_logic;
		out1: out std_logic
	);
	end component MUX2x1;

	signal s_count : std_logic_vector (5 downto 0);
	signal cnt : std_logic_vector (5 downto 0);  --violation
	signal din1,din2,selin : std_logic;
	signal qout: std_logic;
begin



	CLOCK_GENERATE : if CLOCK_ONLY = 1 generate
	cnt_out <= s_count(5 downto 0);
	MUX2x1_inst : MUX2x1
	port map(
		in1 => din1,
		in2 => din2,
		sel => selin,
		out1 => qout
	);
	process(rst_n,clk) is
	begin
		if(rst_n = '0' )then
			s_count <= (others => '0');
		elsif (clk'event and clk = '1')then
			s_count <= s_count + 1;
		end if;
	end process;

    end generate;

end Behavioral;

