  entity R6_2_6_1_3 is
  PORT(
		   clk : in std_logic;
           rst : in std_logic;
		   frm_export_en : in std_logic;
           lo_cos_wave : out std_logic_vector(11 downto 0)
	 ); 
  end R6_2_6_1_3;

  architecture Behavioral of R6_2_6_1_3 is
	signal cos_sig: std_logic_vector(11 downto 0);
	signal data_modu_tmp : std_logic_vector(11 downto 0);
	signal modu_ctl : std_logic_vector(1 downto 0);

  begin
	lo_cos_wave <= cos_sig;
	process(clk,rst)
	begin
		if rst='1' then
			data_modu_tmp <= (others => '0');
		elsif rising_edge(clk) then 
			if frm_export_en='1'then
				case modu_ctl is
					when "0" => data_modu_tmp <= 0- cos_sig;  --violation
					when "01" => data_modu_tmp <= 0+ cos_sig;
					when "10" => data_modu_tmp <= 0+ cos_sig;
					when "11" => data_modu_tmp <= 0- cos_sig;
					when others => data_modu_tmp <= (others => '0');
				end case;
			else
				data_modu_tmp <= (others => '0');
			end if;
		end if;
	end process;	
  end Behavioral;

