  entity R6_2_7_1_3 is
  port( 
		nrst            :in  std_logic;
        clk             :in  std_logic;
		MODE			:in  std_logic;
        DIN             :in  std_logic_vector (3 downto 0);
	   	out_2           :out std_logic_vector (2 downto 0);  
		out_1           :out std_logic
       );
  end R6_2_7_1_3;

  architecture Behavioral of R6_2_7_1_3 is
	signal cnt_reg:integer range 0 to 9 := 0;
	constant expon: integer:= 10;
  begin

  process(nrst) is
  begin
	if(nrst = '0') then
	LOOP
		null;
	end loop;
	end if;
  end process;

  process(clk,nrst) is
  begin
	if(nrst = '0') then
		cnt_reg <= 0;
	elsif rising_edge(clk) then
		LOOP
			cnt_reg <= cnt_reg + 1;
		exit when cnt_reg = 9;
		end loop;
	end if;
  end process;

  process (DIN,MODE)
  variable F:std_logic;
  begin
		F:='0';
	for i in 0 to 3 loop
		if(MODE = '1' and i < 2)then
		out_1 <= DIN(i);
		end if;
		F:= F or DIN(i);
	end loop;
	out_1 <= F;
  end process;

  process (DIN,MODE)
  variable res : integer := '1';
  begin
	while( i < expon) loop
		res := res * 2;
		i := i + 1;
	end loop;

	while( 10) loop   --violation
		res := res * 2;
		i := i + 1;
	end loop;
  end process;

  end Behavioral;

