  entity R6_2_8_1_3 is
  generic(
        constant  GROUP_SIZE    : std_logic := 'X';
		constant  WIDTH_SIZE    : integer := 32
    );
  PORT(
	 clk : in std_logic;
     rst : in std_logic;
	 a : in std_logic_vector(3 downto 0);
     b : out std_logic_vector(3 downto 0)
	 );
  end R6_2_8_1_3;

  architecture Behavioral of R6_2_8_1_3 is
	constant  Con_SIZE    : std_logic := 'X';
  begin

	process(clk,rst)
	begin
		if (rst = '1') then
			b <= (others => '1');
		elsif rising_edge(clk) then 
			b <= a + GROUP_SIZE;
			b <=a * 'X';
			b <= a ** 'Z';
			b <= a / 2;
		end if;
	end process;

  end Behavioral;

