	PORT(
		   clk : in std_logic;
           rst : in std_logic;
		   a_in : in std_logic_vector(3 downto 0);
           b_out : out std_logic_vector(3 downto 0)
	 ); 
  end R6_2_8_1_5;

  architecture Behavioral of R6_2_8_1_5 is
	signal a : std_logic_vector(7 downto 0);
	signal b : std_logic_vector(5 downto 0);
	signal c : std_logic_vector(7 downto 0);

  begin
	c <=a or b;
	process(clk,rst)
	begin
		if (rst = '1') then
			c <= (others => '0');
		elsif rising_edge(clk) then 
			c <= a  xor b nand a_in;  --violation
			c <= a nor b;
			c <= a nand b;
		end if;
	end process;

  end Behavioral;

