  entity R6_2_9_1_3 is
	port (	
	clock, reset: in std_logic;
	data_out: out std_logic;
	data_in: in std_logic_vector (1 downto 0)
	);
  end R6_2_9_1_3;

  architecture behave of R6_2_9_1_3 is

	signal pres_state: std_logic_vector (1 downto 0);
    signal next_state: std_logic_vector (1 downto 0);
	signal test_state: std_logic_vector (1 downto 0);
	signal temp1, temp2 : std_logic_vector(2 downto 0);

  begin

  statereg: process (clock, reset)
  begin
	if (reset = '0') then
		pres_state <= "00";
	elsif (clock'event and clock ='1') then
		pres_state <= next_state;
	end if;
  end process statereg;

  fsm: process (pres_state, data_in)
  begin
	case pres_state is
		    when st0 =>
			     case data_in is
				    when "00" => next_state <= "00";
					when "01" => next_state <= "01";
					when "10" => next_state <= "10";
					when "11" => next_state <= "11";
					when others => next_state <= "00";
				end case;

		    when st1 =>
			     case data_in is
					when "00" => next_state <= "01";
					when "01" => next_state <= "01";
					when "10" => next_state <= "10";
					when "11" => next_state <="10";
					when others => next_state <= "01";
				end case;
		    when st3 =>
				case data_in is
					when "01" => next_state <= "11";
					when "11" => next_state <= "11";
					when others => next_state <= "10";
				end case;
            when others => null;   --violation:程序中状态机进入无效状态后置空操作，可能导致状态机死锁

		end case;

  end process fsm;
  end behave;

