		elsif(clk(0)'event and clk(0) = '1') then	
			q_1 <=  d_1;
		end if;
	end process;

	process(clk(1),nrst)is
	begin
		if(nrst = '0') then
			q_2 <=  '1';
		elsif(clk(1)'event and clk(1) = '1') then	
			q_2 <=  d_2;
		end if;
	end process;
  end Behavioral;

