  entity dff is
	port (
	clk : in std_logic;
	D : in std_logic;
	Q : out std_logic
	);
  end dff;

  architecture basic of dff is
  begin
  process(clk) is
  begin
	if(clk'event and clk = '1') then
	  Q <= D;
	end if;
  end process;
  end basic;

  entity R6_2_11_2_1 is   --violation
